#!/usr/bin/env python3
"""Block `pnpm test` (vitest interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    stripped = cmd.strip()
    is_test = stripped.startswith("pnpm test") or stripped.startswith("pnpm run test")
    if is_test and "test:ci" not in cmd and "vitest run" not in cmd:
        print(
            "Use `pnpm test:ci` instead — `pnpm test` opens the vitest interactive "
            "watcher and hangs until it times out.",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Run `pnpm lint` before any `git commit`; block the commit if lint fails."""
import json, re, subprocess, sys

GIT_COMMIT = re.compile(r"\bgit\s+commit\b")


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if not GIT_COMMIT.search(cmd):
        return 0
    try:
        r = subprocess.run(
            ["pnpm", "lint"],
            capture_output=True, text=True, timeout=120,
            cwd=ev.get("cwd") or None,
        )
    except Exception:
        return 0  # can't run lint (missing pnpm/script) — don't break the commit
    if r.returncode != 0:
        out = (r.stdout + r.stderr).strip()
        print(
            "BLOCKING: `pnpm lint` failed — fix the errors below, then commit. "
            "Do not skip lint.",
            file=sys.stderr,
        )
        if out:
            print(out[-1500:], file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block shell commands that read a .env file (cat/grep/head/source/`< .env` ...),
closing the Bash bypass of the Read-tool permissions.deny rule. Secrets live in .env.local."""
import json, re, sys

READ_CMDS = {
    "cat", "less", "more", "head", "tail", "nl", "tac",
    "od", "xxd", "hexdump", "strings", "grep", "egrep",
    "fgrep", "rg", "ag", "ack", "awk", "sed", "source",
}

ENV_TOKEN = re.compile(r"""(?:^|[\s/="'`])\.env(?:\.[\w.-]+)?\b""")
ENV_REDIR = re.compile(r"""<\s*\S*\.env(?:\.[\w.-]+)?\b""")


def reads_env(cmd: str) -> bool:
    if ENV_REDIR.search(cmd):
        return True
    if not ENV_TOKEN.search(cmd):
        return False
    for tok in re.split(r"[\s|;&()]+", cmd.strip()):
        if tok.rsplit("/", 1)[-1] in READ_CMDS:
            return True
    return False


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name", "") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if reads_env(cmd):
        print(
            "BLOCKING: this command reads a .env file. Real secrets live in .env.local. "
            "Do not read .env files via the shell. Get the value from a non-secret source "
            "or ask the user.",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block a Write/Edit that makes a Python function call itself (direct recursion).

This project's tree walkers must stay iterative: a recursive walk_tree
overflowed Python's recursion limit on a 2000-leaf tree (RecursionError).
"""
import ast, json, sys, textwrap


def self_recursive_funcs(code):
    try:
        tree = ast.parse(textwrap.dedent(code))
    except (SyntaxError, ValueError):
        return []  # partial/unparseable fragment — do not block
    hits = []
    for node in ast.walk(tree):
        if not isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            continue
        for sub in ast.walk(node):
            if (isinstance(sub, ast.Call) and isinstance(sub.func, ast.Name)
                    and sub.func.id == node.name):
                hits.append(node.name)
                break
    return hits


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    if tool not in ("Write", "Edit", "MultiEdit"):
        return 0
    if not str(inp.get("file_path", "")).endswith(".py"):
        return 0

    snippets = []
    if tool == "Write":
        snippets.append(inp.get("content", ""))
    elif tool == "Edit":
        snippets.append(inp.get("new_string", ""))
    else:  # MultiEdit
        for e in inp.get("edits") or []:
            snippets.append(e.get("new_string", ""))

    hits = []
    for s in snippets:
        hits.extend(self_recursive_funcs(s or ""))
    if hits:
        names = ", ".join(sorted(set(hits)))
        print(
            f"BLOCKED: this change makes {names} call itself (direct recursion). "
            "Deep inputs overflow Python's recursion limit — the RecursionError "
            "that broke a 2000-leaf tree here. Rewrite with an explicit "
            "stack/worklist loop, or add an explicit depth bound, then retry.",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After a Write/Edit/MultiEdit on a .py file, run `ruff format` to auto-fix
formatting, then surface any residual `ruff check` errors back to Claude."""
import json, subprocess, sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name") not in ("Write", "Edit", "MultiEdit"):
        return 0
    path = (ev.get("tool_input") or {}).get("file_path", "")
    if not path.endswith(".py"):
        return 0
    try:
        subprocess.run(["ruff", "format", path], capture_output=True, text=True, timeout=10)
        check = subprocess.run(["ruff", "check", path], capture_output=True, text=True, timeout=10)
    except Exception:
        return 0  # ruff missing or errored — never break Claude Code
    if check.returncode != 0:
        detail = (check.stdout or check.stderr or "").strip()
        print(f"BLOCKING: `ruff check` still fails on {path} after `ruff format`:", file=sys.stderr)
        if detail:
            print(detail, file=sys.stderr)
        print("Fix each issue, then re-run `ruff check`. Do not stop until it passes.", file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit touches an exported identifier, grep the codebase for
references (by name, and by OLD string value on a value change) and surface them."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)")
STR_CONST = re.compile(r"export\s+const\s+(\w+)\s*(?::[^=]+)?=\s*['\"]([^'\"]+)['\"]")

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [
        {"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}
    ]

    terms: set[str] = set()
    for e in edits:
        old, new = e.get("old_string", ""), e.get("new_string", "")
        for s in (old, new):
            m = EXPORT_DEF.search(s)
            if m:
                terms.add(m.group(1))
        om, nm = STR_CONST.search(old), STR_CONST.search(new)
        if om and nm and om.group(1) == nm.group(1) and om.group(2) != nm.group(2):
            terms.add(om.group(2))  # old value — hardcoded callers break on it
    if not terms:
        return 0

    findings = []
    for term in sorted(terms):
        try:
            r = subprocess.run(
                ["grep", "-rnw", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx", term, "."],
                capture_output=True, text=True, timeout=5,
            )
        except Exception:
            continue
        hits = [l for l in r.stdout.splitlines() if l][:20]
        if hits:
            findings.append((term, hits))
    if not findings:
        return 0

    total = sum(len(h) for _, h in findings)
    print(f"BLOCKING: {total} reference(s) may now be stale after this export change:", file=sys.stderr)
    for term, hits in findings:
        print(f"`{term}`:", file=sys.stderr)
        for h in hits:
            print(f"  {h}", file=sys.stderr)
    print("Fix each, then summarize. Do not stop. Do not ask.", file=sys.stderr)
    return 2

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block Write/Edit/MultiEdit when the new content contains a hardcoded secret.
Steer Claude to process.env + .env.example per CLAUDE.md."""
import json, re, sys

PROVIDER = [
    r"sk-[A-Za-z0-9_-]{20,}",              # OpenAI (incl. sk-proj-)
    r"AKIA[0-9A-Z]{16}",                   # AWS access key id
    r"gh[pousr]_[A-Za-z0-9]{36,}",         # GitHub token
    r"xox[baprs]-[A-Za-z0-9-]{10,}",       # Slack token
    r"AIza[0-9A-Za-z_-]{35}",              # Google API key
    r"sk_live_[0-9A-Za-z]{16,}",           # Stripe secret key
    r"-----BEGIN [A-Z ]*PRIVATE KEY-----", # PEM private key
]
PROVIDER_RE = re.compile("|".join(PROVIDER))
ASSIGN_RE = re.compile(
    r"(?i)(api[_-]?key|secret|token|password|passwd|access[_-]?key|client[_-]?secret)"
    r"\s*[:=]\s*(['\"])([^'\"]{12,})\2"
)
PLACEHOLDER = ("your", "example", "placeholder", "changeme",
               "dummy", "xxxx", "<", "${", "redacted")

def secret_in(text):
    if PROVIDER_RE.search(text):
        return True
    for m in ASSIGN_RE.finditer(text):
        low = m.group(3).lower()
        if any(p in low for p in PLACEHOLDER):
            continue
        return True
    return False

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    if tool not in ("Write", "Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    if tool == "Write":
        text = inp.get("content", "")
    elif tool == "Edit":
        text = inp.get("new_string", "")
    else:
        text = "\n".join((e or {}).get("new_string", "")
                         for e in (inp.get("edits") or []))
    if secret_in(text):
        print("BLOCKED: this write contains a hardcoded secret (API key, token, or "
              "private key). CLAUDE.md requires secrets to come from process.env and be "
              "documented in .env.example. Replace the literal with an env-var reference, "
              "then retry.", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block git commits whose subject is a multi-line paragraph or exceeds 72
chars; steer Claude toward a short imperative subject line."""
import json, shlex, sys

MAX = 72

def extract_message(cmd):
    try:
        toks = shlex.split(cmd)
    except Exception:
        return None
    if "commit" not in toks:
        return None
    for i, t in enumerate(toks):
        if t in ("-m", "--message") and i + 1 < len(toks):
            return toks[i + 1]
        if t.startswith("--message="):
            return t[len("--message="):]
    return None

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if "commit" not in cmd:
        return 0
    msg = extract_message(cmd)
    if not msg or "$(" in msg:
        return 0  # editor-mode / command-substitution / unparseable: don't block
    first_para = msg.split("\n\n", 1)[0].strip()
    if not first_para:
        return 0
    multiline = "\n" in first_para
    too_long = len(first_para.splitlines()[0]) > MAX
    if multiline or too_long:
        print(
            "Commit subject is a paragraph / too long. Rewrite as a single short "
            "imperative subject line (≤%d chars), e.g. \"Refactor auth: extract "
            "token validation\". Put any detail in the body after a blank line, then "
            "re-run the commit." % MAX,
            file=sys.stderr,
        )
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block any call to staging-api.internal (WebFetch URL or Bash curl/wget).

CLAUDE.md forbids hitting the shared staging API from agent sessions because
some endpoints mutate state. Telemetry shows this rule was violated via WebFetch
anyway, so enforce it deterministically before the tool runs.
"""
import json, sys

HOST = "staging-api.internal"

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool == "WebFetch":
        target = inp.get("url", "")
    elif tool == "Bash":
        target = inp.get("command", "")
    else:
        return 0

    if HOST in target:
        print(
            f"Blocked: `{HOST}` is a shared, state-mutating environment and is "
            "off-limits to agent sessions (see CLAUDE.md). Use recorded fixtures "
            "or the local mock server instead.",
            file=sys.stderr,
        )
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

