#!/usr/bin/env python3
"""Block `git add`/`git commit` that stages the real `.env` (allows `.env.example`)."""
import json, re, sys

GIT_STAGE = re.compile(r"\bgit\s+(?:add|commit)\b")
ENV_TOKEN = re.compile(r"(?:^|[\s/])\.env(?![\w.])")

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if not GIT_STAGE.search(cmd):
        return 0
    cleaned = cmd.replace('"', " ").replace("'", " ")
    if ENV_TOKEN.search(cleaned):
        print(
            "BLOCKING: this git command stages the real `.env`, which must never "
            "be committed (CLAUDE.md). Remove `.env` (commit `.env.example` "
            "instead), then proceed. Do not commit `.env`.",
            file=sys.stderr,
        )
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After editing a .py file, run pyflakes to catch undefined names / import
errors before they reach the user. Fails open if pyflakes is not installed."""
import json, os, subprocess, sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name") not in ("Edit", "MultiEdit", "Write"):
        return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "") or ""
    if not path.endswith(".py") or not os.path.isfile(path):
        return 0
    try:
        r = subprocess.run(
            [sys.executable, "-m", "pyflakes", path],
            capture_output=True, text=True, timeout=10,
        )
    except Exception:
        return 0  # pyflakes unavailable / slow — fail open, never block the edit
    out = (r.stdout + r.stderr).strip()
    if not out or "No module named pyflakes" in out:
        return 0  # clean file, or pyflakes not installed
    print("REQUIRED FOLLOW-UP: pyflakes flagged the Python file you just edited:", file=sys.stderr)
    print(out, file=sys.stderr)
    print("Fix each issue, then proceed. Do not stop. Do not ask.", file=sys.stderr)
    return 2


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Before a `git commit`, run the test suite (CLAUDE.md mandates pytest before
committing) and block the commit if tests fail. Fails open on timeout / missing
pytest / no tests collected so it never wedges an otherwise-valid commit."""
import json, re, subprocess, sys

GIT_COMMIT = re.compile(r"\bgit\s+commit\b")


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "") or ""
    if not GIT_COMMIT.search(cmd):
        return 0
    try:
        r = subprocess.run(
            [sys.executable, "-m", "pytest", "-q"],
            capture_output=True, text=True, timeout=120,
        )
    except Exception:
        return 0  # pytest missing / timed out — fail open, don't wedge commits
    # pytest exit codes: 0 = passed, 5 = no tests collected. Otherwise = failure.
    if r.returncode in (0, 5):
        return 0
    tail = "\n".join((r.stdout + r.stderr).strip().splitlines()[-25:])
    print("BLOCKING: `python -m pytest` failed — CLAUDE.md requires passing tests before committing.", file=sys.stderr)
    print(tail, file=sys.stderr)
    print("Fix the failing tests, then retry the commit. Do not skip the test gate to commit anyway.", file=sys.stderr)
    return 2


if __name__ == "__main__":
    sys.exit(main())
